sect2.example:
    Użycie self::


<?php

class A
{
    public static function who()
    {
        echo __CLASS__;
    }

    public static function test()
    {
        self::who();
    }
}

class B extends A
{
    public static function who()
    {
        echo __CLASS__;
    }
}

B::test();

?>


    &example.outputs;


A

    Proste użycie static::


<?php

class A
{
    public static function who()
    {
        echo __CLASS__;
    }

    public static function test()
    {
        static::who(); // Tutaj działa późne wiązanie statyczne
    }
}

class B extends A
{
    public static function who()
    {
        echo __CLASS__;
    }
}

B::test();

?>


    &example.outputs;


B

    Użycie static:: w kontekście niestatycznym


<?php

class A
{
    private function foo()
    {
        echo "Success!\n";
    }

    public function test()
    {
        $this->foo();
        static::foo();
    }
}

class B extends A
{
    /* foo() zostanie skopiowane do B, więc jego zasięg nadal będzie A
    * i wywołanie zakończy się powodzeniem */
}

class C extends A
{
    private function foo()
    {
        /* Oryginalna metoda jest zastąpiona; zasięgiem nowej jest C */
    }
}

$b = new B();
$b->test();

$c = new C();
try {
    $c->test();
} catch (Error $e) {
    echo $e->getMessage();
}

?>


    &example.outputs;


Success!
Success!
Success!
Call to private method C::foo() from scope A

note.example:
     Wywołania przekazujące i nieprzekazujące


<?php

class A
{
    public static function foo()
    {
        static::who();
    }

    public static function who()
    {
        echo __CLASS__ . "\n";
    }
}

class B extends A
{
    public static function test()
    {
        A::foo();
        parent::foo();
        self::foo();
    }

    public static function who()
    {
        echo __CLASS__ . "\n";
    }
}

class C extends B
{
    public static function who()
    {
        echo __CLASS__ . "\n";
    }
}

C::test();

?>


     &example.outputs;


A
C
C
